        defer input.deinit();
        var linear_input = try retainedLinearInputView(&input, request.in_dim);
        defer linear_input.deinit();
        const tensor = (try metal_runtime.decoderRuntimeApplyLinear(self.provider_impl, .{
            .slot = request.slot,
            .input = linear_input,
