    fn decoderRuntimeApplyLinearPairOp(ctx: *anyopaque, request: *const ops.DecoderRuntimeApplyLinearPairRequest) anyerror!?ops.LinearNoBiasPairResult {
        const self: *MetalCompute = @ptrCast(@alignCast(ctx));
        var input = try self.ownedMetalTensorFromCt(request.input);
        defer input.deinit();
        var linear_input = try retainedLinearInputView(&input, request.in_dim);
        defer linear_input.deinit();
        const rows: usize = @intCast(linear_input.dim(0));
        const dense_active_frame_pair = rows > 1 and linear_input.isDevice() and
            metal_runtime.hasActiveFrame(self.provider_impl.raw_decode_runtime) and
            self.provider_impl.raw_linear_slot_kinds[request.slot_a] == .dense and
            self.provider_impl.raw_linear_slot_kinds[request.slot_b] == .dense;
        if (try metal_runtime.tryApplyQuantizedRuntimeLinearPair(
            self.provider_impl,
            request.slot_a,
            request.slot_b,
            linear_input,
            rows,
            request.in_dim,
            request.out_dim,
        )) |pair| {
            return .{
                .first = try self.ctFromOwnedMetalTensor(pair.first),
                .second = try self.ctFromOwnedMetalTensor(pair.second),
            };
        }
        if (try metal_runtime.tryApplyDenseRuntimeLinearPair(
            self.provider_impl,
            request.slot_a,
            request.slot_b,
            linear_input,
            rows,
            request.in_dim,
            request.out_dim,
        )) |pair| {
            return .{
                .first = try self.ctFromOwnedMetalTensor(pair.first),
                .second = try self.ctFromOwnedMetalTensor(pair.second),
            };
        }
        if (dense_active_frame_pair) {
            self.timing_stats.metal_runtime_dense_pair_packed_fallbacks += 1;
            return null;
        }

        const first = (try decoderRuntimeApplyLinearOp(ctx, &.{
            .slot = request.slot_a,
            .input = request.input,
            .in_dim = request.in_dim,
            .out_dim = request.out_dim,
        })) orelse return null;
        errdefer freeOp(ctx, first);
        const second = (try decoderRuntimeApplyLinearOp(ctx, &.{
            .slot = request.slot_b,
            .input = request.input,
            .in_dim = request.in_dim,
            .out_dim = request.out_dim,
        })) orelse {
            freeOp(ctx, first);
            return null;
        };
        return .{
            .first = first,
            .second = second,
        };
    }

    fn decoderRuntimeApplyLinearQkvOp(ctx: *anyopaque, request: *const ops.DecoderRuntimeApplyLinearQkvRequest) anyerror!?ops.LinearNoBiasTripleResult {
        const self: *MetalCompute = @ptrCast(@alignCast(ctx));
        var input = try self.ownedMetalTensorFromCt(request.input);
        defer input.deinit();
        var linear_input = try retainedLinearInputView(&input, request.in_dim);
        defer linear_input.deinit();
        const rows: usize = @intCast(linear_input.dim(0));
        const dense_active_frame_qkv = rows > 1 and linear_input.isDevice() and
            metal_runtime.hasActiveFrame(self.provider_impl.raw_decode_runtime) and
            self.provider_impl.raw_linear_slot_kinds[request.q_slot] == .dense and
            self.provider_impl.raw_linear_slot_kinds[request.k_slot] == .dense and
            self.provider_impl.raw_linear_slot_kinds[request.v_slot] == .dense;
        if (rows > 1 and metal_runtime.hasActiveFrame(self.provider_impl.raw_decode_runtime)) {
            if (try metal_runtime.tryApplyQuantizedRuntimeLinearQkvScratch(
                self.provider_impl,
                request.q_slot,
                request.k_slot,
                request.v_slot,
                linear_input,
                rows,
                request.in_dim,
                request.q_out_dim,
                request.kv_out_dim,
            )) |triple| {
                return .{
                    .first = try self.ctFromOwnedMetalTensor(triple.first),
                    .second = try self.ctFromOwnedMetalTensor(triple.second),
                    .third = try self.ctFromOwnedMetalTensor(triple.third),
                };
            }
        }
        if (try metal_runtime.tryApplyQuantizedRuntimeLinearQkv(
            self.provider_impl,
            request.q_slot,
            request.k_slot,
            request.v_slot,
            linear_input,
            rows,
            request.in_dim,
            request.q_out_dim,
            request.kv_out_dim,
        )) |triple| {
            return .{
                .first = try self.ctFromOwnedMetalTensor(triple.first),
                .second = try self.ctFromOwnedMetalTensor(triple.second),
                .third = try self.ctFromOwnedMetalTensor(triple.third),
            };
        }
        if (try metal_runtime.tryApplyDenseRuntimeLinearQkv(
            self.provider_impl,
            request.q_slot,
            request.k_slot,
            request.v_slot,
            linear_input,
            rows,
            request.in_dim,
            request.q_out_dim,
            request.kv_out_dim,
        )) |triple| {
            return .{
                .first = try self.ctFromOwnedMetalTensor(triple.first),
                .second = try self.ctFromOwnedMetalTensor(triple.second),
                .third = try self.ctFromOwnedMetalTensor(triple.third),
            };
        }
        if (dense_active_frame_qkv) {
            self.timing_stats.metal_runtime_dense_qkv_packed_fallbacks += 1;
            return null;
        }
        if (try metal_runtime.tryApplyDenseRuntimeLinear(
            self.provider_impl,
            request.q_slot,
            linear_input,
            rows,
            request.in_dim,
            request.q_out_dim,
        )) |q_out| {
            errdefer {
                var q_out_mut = q_out;
                q_out_mut.deinit();
            }
            if (try metal_runtime.tryApplyDenseRuntimeLinearPair(
                self.provider_impl,
                request.k_slot,
                request.v_slot,
                linear_input,
                rows,
                request.in_dim,
                request.kv_out_dim,
            )) |kv_out| {
                return .{
                    .first = try self.ctFromOwnedMetalTensor(q_out),
                    .second = try self.ctFromOwnedMetalTensor(kv_out.first),
                    .third = try self.ctFromOwnedMetalTensor(kv_out.second),
                };
            }
        }

        const first = (try decoderRuntimeApplyLinearOp(ctx, &.{
            .slot = request.q_slot,
            .input = request.input,
            .in_dim = request.in_dim,
            .out_dim = request.q_out_dim,
        })) orelse return null;
        errdefer freeOp(ctx, first);
        const second = (try decoderRuntimeApplyLinearOp(ctx, &.{
            .slot = request.k_slot,
            .input = request.input,
            .in_dim = request.in_dim,
            .out_dim = request.kv_out_dim,
        })) orelse {
            freeOp(ctx, first);
            return null;
        };
        errdefer {
            freeOp(ctx, first);
            freeOp(ctx, second);
        }
        const third = (try decoderRuntimeApplyLinearOp(ctx, &.{
            .slot = request.v_slot,
            .input = request.input,
            .in_dim = request.in_dim,
            .out_dim = request.kv_out_dim,
        })) orelse {
            freeOp(ctx, first);
            freeOp(ctx, second);
            return null;
        };
        return .{
            .first = first,
            .second = second,
            .third = third,
        };
    }

